urlset:
{# Always emit the homepage first — index.md uses `template: home.html` and may
   be skipped or under-prioritised by some build pipelines. Hard-coding the
   site root guarantees AI crawlers and search engines see it. #}

         {{ config.site_url|e }}
         {%- if build_date_utc %}
         {{ build_date_utc.strftime('%Y-%m-%d') }}
         {%- endif %}
         weekly
         1.0

{%- for file in pages -%}
    {%- if not file.page.is_link and not file.page.is_homepage and (file.page.abs_url or file.page.canonical_url) %}

         {% if file.page.canonical_url %}{{ file.page.canonical_url|e }}{% else %}{{ file.page.abs_url|e }}{% endif %}
         {%- if file.page.update_date %}
         {{ file.page.update_date }}
         {%- endif %}

    {%- endif -%}
{% endfor %}
